/* eslint-disable no-console */

/**
 * Minimal Markdown → HTML for pipeline reports generated by Many (main process).
 * Supports headings, bold/italic/code, links, ordered/unordered lists and GFM
 * tables — enough to render the agent's structured report into a self-contained,
 * exportable artifact. Kept dependency-free (no remark) so it is safe in main.
 */

function escapeHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function inlineMd(s) {
  return s
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/(^|[^*])\*([^*]+)\*/g, '$1<em>$2</em>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
}

const isTableRow = (s) => /^\s*\|.*\|\s*$/.test(s);
const isTableSeparator = (s) => /^\s*\|?\s*:?-{1,}:?\s*(\|\s*:?-{1,}:?\s*)+\|?\s*$/.test(s);
const splitTableCells = (row) =>
  row.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map((c) => c.trim());

function markdownToHtml(md) {
  const lines = escapeHtml(md).split(/\r?\n/);
  const out = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    if (/^\s*$/.test(line)) { i++; continue; }
    const heading = line.match(/^\s*(#{1,6})\s+(.*)$/);
    if (heading) {
      out.push(`<h${heading[1].length}>${inlineMd(heading[2])}</h${heading[1].length}>`);
      i++;
      continue;
    }
    if (/^\s*[-*]\s+/.test(line)) {
      const items = [];
      while (i < lines.length && /^\s*[-*]\s+/.test(lines[i])) {
        items.push(`<li>${inlineMd(lines[i].replace(/^\s*[-*]\s+/, ''))}</li>`);
        i++;
      }
      out.push(`<ul>${items.join('')}</ul>`);
      continue;
    }
    if (/^\s*\d+\.\s+/.test(line)) {
      const items = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) {
        items.push(`<li>${inlineMd(lines[i].replace(/^\s*\d+\.\s+/, ''))}</li>`);
        i++;
      }
      out.push(`<ol>${items.join('')}</ol>`);
      continue;
    }
    if (isTableRow(line) && i + 1 < lines.length && isTableSeparator(lines[i + 1])) {
      const headers = splitTableCells(line);
      i += 2;
      const rows = [];
      while (i < lines.length && isTableRow(lines[i])) { rows.push(splitTableCells(lines[i])); i++; }
      const thead = `<thead><tr>${headers.map((h) => `<th>${inlineMd(h)}</th>`).join('')}</tr></thead>`;
      const tbody = `<tbody>${rows
        .map((r) => `<tr>${r.map((c) => `<td>${inlineMd(c)}</td>`).join('')}</tr>`)
        .join('')}</tbody>`;
      out.push(`<table class="md-table">${thead}${tbody}</table>`);
      continue;
    }
    const para = [];
    while (
      i < lines.length &&
      !/^\s*$/.test(lines[i]) &&
      !/^\s*(#{1,6})\s+/.test(lines[i]) &&
      !/^\s*[-*]\s+/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i]) &&
      !isTableRow(lines[i])
    ) { para.push(lines[i]); i++; }
    out.push(`<p>${inlineMd(para.join(' '))}</p>`);
  }
  return out.join('\n');
}

/** Wrap rendered markdown in a styled, self-contained, exportable HTML document. */
function buildReportHtml(title, subtitle, markdown) {
  const body = markdownToHtml(markdown || '');
  const footerDate = new Date().toLocaleString();
  return `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>${escapeHtml(title)}</title>
<style>
  /* Use Dome's theme variables (injected by the artifact host so the report
     adapts to light/dark). Fallbacks make the standalone exported HTML a clean
     light document. */
  *{box-sizing:border-box;}
  body{margin:0;background:var(--background, #fbfbfe);color:var(--muted-foreground, #4a4766);font-family:var(--font-sans, -apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif);line-height:1.6;padding:2rem 1rem;}
  .report{max-width:820px;margin:0 auto;background:var(--card, #f2f2f9);border:1px solid var(--border, #dcdce8);border-radius:14px;overflow:hidden;}
  .header{padding:1.5rem 2rem;border-bottom:1px solid var(--border, #dcdce8);}
  .header h1{margin:0;font-size:1.5rem;color:var(--foreground, #040316);}
  .header .sub{margin:.25rem 0 0;color:var(--muted-foreground, #858299);font-size:.9rem;}
  .content{padding:1.5rem 2rem;}
  .content h1,.content h2,.content h3{margin:1.25rem 0 .6rem;line-height:1.3;color:var(--foreground, #040316);}
  .content h1{font-size:1.4rem;} .content h2{font-size:1.2rem;} .content h3{font-size:1.05rem;}
  .content p{margin:0 0 .8rem;}
  .content ul,.content ol{margin:0 0 .8rem;padding-left:1.4rem;}
  .content li{margin:.2rem 0;}
  .content code{background:var(--muted, #e8e8f2);padding:.1rem .35rem;border-radius:4px;font-size:.85em;color:var(--primary, #7b76d0);}
  .content strong{color:var(--foreground, #040316);}
  .content a{color:var(--primary, #7b76d0);}
  .md-table{width:100%;border-collapse:collapse;margin:0 0 1rem;font-size:.92em;}
  .md-table th,.md-table td{border:1px solid var(--border, #dcdce8);padding:.45rem .65rem;text-align:left;vertical-align:top;color:var(--muted-foreground, #4a4766);}
  .md-table th{background:var(--muted, #e8e8f2);color:var(--foreground, #040316);font-weight:600;}
  .footer{padding:1rem 2rem;color:var(--muted-foreground, #858299);font-size:.78rem;border-top:1px solid var(--border, #dcdce8);}
</style>
</head>
<body>
<main class="report">
  <header class="header">
    <h1>${escapeHtml(title)}</h1>
    ${subtitle ? `<p class="sub">${escapeHtml(subtitle)}</p>` : ''}
  </header>
  <div class="content">${body}</div>
  <footer class="footer">Generado por Many · ${escapeHtml(footerDate)}</footer>
</main>
</body>
</html>`;
}

module.exports = { markdownToHtml, buildReportHtml, escapeHtml };
